script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', null, 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f.getItem('d46')._controlBehavior.add_onRender(on$Voucher$GridRender);
  f.getItem('f46')._controlBehavior.add_onRender(on$Voucher$ChargeRender);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;

      &PaymentRequestCustomerIdentity;
      &VoucherLogHandleStatus;
      &ListCreate;
      &PostCreate;


}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&PaymentRequestCustomerIdentity;&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.getItem('d46')._controlBehavior.remove_onRender(on$Voucher$GridRender);} catch (ex) {}
  try {f.getItem('f46')._controlBehavior.remove_onRender(on$Voucher$ChargeRender);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}

function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d46')._controlBehavior, y = f.getItem('f46')._controlBehavior;
  switch (action) {
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Save':
      set$Voucher$EmptyControlField(f, g, 'so_hd', '1');
      set$Voucher$EmptyControlField(f, g, 'ma_kh_i', '3');
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$Voucher$GridRender(sender, eventArgs) {set$Voucher$GridColumns(eventArgs.grid);}
function on$Voucher$ChargeRender(sender, eventArgs) {set$Voucher$ChargeColumn(sender.get_element().parentForm, 'f46', ['ty_gia'])};
/* </flatten> */
      &ScriptVoucherNumber;
      &ScriptExchangeRate;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d46')._controlBehavior, y = f.getItem('f46')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.ExchangeRate, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency}, null, null, c);
    v.set_currencyFields('t_tien_nt:t_tien');
    v.addGridFields(g, 'tien_nt:tien');
    v.addGridFields(y, 'tien_cp_nt,t_thue_nt:tien_cp,t_thue');

    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'],['t_tien', 'tien']]);
    v.set_referenceFields(null);
    v.set_executeExpression(null);
    v.init();
    v.setFormLayout(0);
    this.init(f);
  },
  onCurrencyChanged: function(sender, e) {
    this.onCurrencySelected(sender, e);
    var c = e.object, f = c._currency.parentForm;
    if (c._baseCurrency == e.type) {
      c._exchangeRate._controlBehavior._set_number(1);
      c.onExchangeRateChanged();
      if (f.getItemValue('loai_ct') == '2') onExchangeRateExternal(false, f);
    }
    else {
      var d = f.getItemValue('ngay_lct');
      if (d) f.request('GetExchangeRate', 'GetExchangeRate', ['ma_nt', 'ngay_lct']);
    }
    set$Voucher$DependOnVoucherType(f);
    set$Voucher$ChargeColumn(f, 'f46', ['ty_gia']);
  },
  onDateChanged: function(sender, e) {
    var c = e.object, f = c._currency.parentForm;
    if (e.type && (c._currency.value != c._baseCurrency)) f.request('GetExchangeRate', 'DateChanged', ['ma_nt', 'ngay_lct']);
  },
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d46', 'hd_yn'], 'ma_tt', ['f46', 'hd_yn'], 'so_ct_goc'&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d46', 'ma_tt', 'f46', 'so_ct_goc'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {
  var f = o.parentForm, v = $func.trim(f.getItemValue('loai_ct'));
  f.request('Customer', 'Customer', ['ma_kh'], o);
  if (v == 1) set$Voucher$Customer$EmptyInvoice(f.getItem('d46')._controlBehavior, 'so_hd', 'tk_co');
}
function onChange$Voucher$Date(o) {
  var f = o.parentForm; v = $func.trim(f.getItemValue('loai_ct')), g = f.getItem('d46');
  if (v == 1 && g && g._activeCell) set$Voucher$Customer$KeyFilter(g._controlBehavior, 'so_hd');
}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem('d46')._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
    g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
function onChange$Voucher$VoucherType(o) {
  var f = o.parentForm;
  set$Voucher$DependOnVoucherType(f);
  set$Voucher$ChargeColumn(f, 'f46', ['ty_gia']);
}
function onchange$Item$(o) {
  if (o.value == '2') {
    var f = o.parentForm, g = f.getItem('d46')._controlBehavior, r = g._rowCount, c = 'tk_co';
    if (r == 1 && g._getItemValue(1, g._getColumnOrder(c)) == '') {
      var i = g._getItem(r, 1);
      i.row = r;
      g.setItemGridBehavior(i, [[c, f.getItemValue('tk_ex'), f.getItemValue('ten_tk_ex'), false]]);
    }
  }
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context){
    case 'Loading':
      &VoucherNumberLoading;
      set$Voucher$ExchangeRateDisabled(f);
      set$Voucher$PaymentControl(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      set$Voucher$DependOnVoucherType(f);
      set$Voucher$PaymentControl(f);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &ListResponseTicket;
      &VoucherNumberReading;

    case 'Rendering':
      if (result[1]) f._currencyBehavior.onRender();
      break;
    case 'GetExchangeRate':
      f._currencyBehavior.onExchangeRateResponse(0, result[0].Value);
      if (f.getItemValue('loai_ct') == '2') onExchangeRateExternal(false, f);
      break;
    case 'DateChanged':
      f._currencyBehavior.onExchangeRateResponse(1, result[0].Value);
      if (f.getItemValue('loai_ct') == '2') onExchangeRateExternal(false, f);
      break;


    case 'Customer':
      f.setItemControlBehavior('ma_tt0', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ong_ba', result[2].Value, null, true);
      f.setItemControlBehavior('dia_chi', result[3].Value, null, true);

      f.setItemValues('tk_ex, ten_tk_ex, tk_cn_ex', [result[4].Value, result[5].Value, result[6].Value]);
      onchange$Item$(f.getItem('loai_ct'));

      f.live(f.getItem('dia_chi'));
      break;
    default:
      break;
  }
}

      /* <flatten type="Javascript"> */
function onChange$Voucher$PaymentControl(o) {
  var f = o.parentForm, v = f.getItemValue('hd_yn'), n = f.getItem('so_ct0');
  set$Voucher$PaymentControl(f);
  if (v) {
    f.setItemControlBehavior('ma_tt', f.getItemValue('ma_tt0'), f.getItemValue('ten_tt0'), true);
    f.setItemValue('ngay_ct0', f.getItemValue('ngay_ct'));
    n.value = f.getItemValue('so_ct');
  }
  else {
    f.setItemControlBehavior('ma_tt', '', '', false);
    n.value = '';
    f.setItemValue('ngay_ct0', null);
  }
}
function set$Voucher$PaymentControl(f) {
  var v = f.getItemValue('hd_yn'), t = f.getItem('ma_tt'), d = f.getItem('ngay_ct0'), n = f.getItem('so_ct0');
  if (f._action != 'View') {
    f._setReadOnly(t, !v);
    f._setReadOnly(d, !v);
  }
  t.disabled = d.disabled = n.disabled = !v;
  d.field.AllowNulls =  t.field.AllowNulls = !v;
}
function set$Voucher$DependOnVoucherType(f) {
  var g = f.getItem('d46')._controlBehavior;
  set$Voucher$ExchangeRateDisabled(f, true);
  set$Voucher$GridColumns(g);
}
function set$Voucher$ExchangeRateDisabled(f, force) {
  if (f._action != 'View') {
    var v = f.getItemValue('loai_ct'), c = f.getItemValue('ma_nt'), o = f.getItem('hd_yn');
    f.getItem('sua_tg_yn').disabled = (c == f._baseCurrency || v == '3' || v == '9');
    o.disabled = (v == 1);
    if (v == 1) {
      f.setItemValue('hd_yn', false);
      if (force) onChange$Voucher$PaymentControl(o);
    }
  }
}
/* </flatten> */
function set$Voucher$GridColumns(g) {
  var f = g.get_element().parentForm, v = f.getItemValue('loai_ct'), h = visible$Voucher$ExchangeRateColumn(f), a = ['so_hd', 'ngay_hd', 'tien_hd_nt', 'da_tt_nt', 'cl_nt', 'ma_nt_i', 'tt_qd'];
  g._suspendLayout();
  g._setColumnVisible(g._getColumnOrder('ma_kh_i'), (v == 3));
  g._setColumnVisible(g._getColumnOrder('ten_kh_i%l'), (v == 3));
  g._setColumnVisible(g._getColumnOrder('ty_gia_ht2'), h);
&PaymentRequestHidden;
  for (var i = 0; i < a.length; i++) {
    g._setColumnVisible(g._getColumnOrder($func.trim(a[i])), (v == 1));
  }
  g._setColumnVisible(g._getColumnOrder('ten_tk%l'), (v != 1));
  g._resumeLayout();
}
/* <flatten type="Javascript"> */
function set$Voucher$ChargeColumn(f, n, c) {
  var g = f.getItem(n)._controlBehavior, h = visible$Charge$ExchangeRateColumn(f), v = f.getItemValue('loai_ct');
  g._suspendLayout();
  for (var i = 0; i < c.length; i++) {
    g._setColumnVisible(g._getColumnOrder($func.trim(c[i])), h);
  }
  g._setColumnVisible(g._getColumnOrder('hd_ln'), (v == '1'));
  g._resumeLayout();
}
function visible$Voucher$ExchangeRateColumn(f) {
  var v = f.getItemValue('loai_ct');
  return ((v == 2) && f.getItem('ma_nt').value != f._baseCurrency);
}
function visible$Charge$ExchangeRateColumn(f) {
  var v = f.getItemValue('loai_ct');
  return (('12'.indexOf(v) > -1) && f.getItem('ma_nt').value != f._baseCurrency);
}

function set$Voucher$ExchangeRate(f) {
  var g = f.getItem('d46')._controlBehavior;
  set$Grid$ExchangeRate(f, g, 'serialize', 'ty_gia_ht2', g.$a.tien_tggs, [g.$a.t_tien]);
}
function set$Charge$ExchangeRate(f) {
  var g = f.getItem('f46')._controlBehavior;
  set$Grid$ExchangeRate(f, g, 'analyze', 'ty_gia');
}
function set$Grid$ExchangeRate(f, g, item, column, assign, aggregate) {
  var v = f.getItemValue(item), r, l = g._getColumnOrder(column);
  if (v == '') return;
  f.setItemValue(item, '');
  var a = v.split('$');
  if ($func.trim(a[0]) == '') return;
  var d = a[0].split(';');
  for (var i = 0; i < d.length; i++) {
    if (i < g._rowCount) {
      var k = $func.trim(d[i]).split(':');
      if (k.length == 1) {
        r = parseFloat(k[0]);
        g._setItemValue(i + 1, l, r);
        if (assign) g.assignExpression(i, assign);
      }
    }
  }
  if (aggregate) g.executeAggregate(aggregate);
}


function onExchangeRateExternal(o, f) {
  if (o) f = o.parentForm;
  var g = f.getItem('f46')._controlBehavior;
  for (var i = 0; i < g._rowCount; i++) {
    obj = g._getItem(i + 1, g._getColumnOrder('tien_cp_nt'));
    obj.row = i + 1;
    g.executeExpression(obj, [g.$a.tien_cp, g.$a.thue_tg]);
  }
}
function focusErrorCharge(f, name, s, r) {
  var z = f.getItem(name)._controlBehavior, l0 = z._getColumnOrder(s);
  f._errorWarningObject = null;
  for (var i = 0; i < z._rowCount; i++) {
    var row = i + 1;
    if (r == i + 1) {
      f._errorWarningObject = z._getItem(row, l0);
      break;
    }
  }
  if (f._errorWarningObject) {
    f.focus(name);
    f._errorWarningObject.focus();
  }
}
/* </flatten> */
