if exists(select 1 from dmkh where ma_kh = @ma_kh) begin
  select rtrim(a.ma_tt) as ma_tt, rtrim(b.ten_tt%l) as ten_tt%l, rtrim(doi_tac) as ong_ba, rtrim(a.dia_chi) as dia_chi, rtrim(a.tk) as tk, rtrim(c.ten_tk%l) as ten_tk%l, c.tk_cn from dmkh a left join dmtt b on a.ma_tt = b.ma_tt left join dmtk c on a.tk = c.tk where a.ma_kh = @ma_kh
  return
